  1→.home-parent-container{
  2→    position: relative;
  3→    display: flex;
  4→    justify-content: flex-start;
  5→    align-items: center;
  6→    position: relative;
  7→    width: 100%;
  8→    height: 100vh;
  9→    overflow-y: auto;
 10→    overflow-x: hidden;  
 11→}
 12→.uploading-bg{
 13→    position: absolute;
 14→    display: flex;
 15→    justify-content: center;
 16→    align-items: center;
 17→    background-color: var(--bg-overlay);
